<!DOCTYPE html>\n<html lang="en">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>Add Tourist</title>\n    <link rel="stylesheet" href="style.css"> <!-- Assuming a common stylesheet for styling -->\n</head>\n<body>\n    <h1>Add Tourist</h1>\n    <form action="send_credentials.php" method="POST">\n        <label for="name">Tourist Name:</label>\n        <input type="text" id="name" name="name" required>\n\n        <label for="email">Email:</label>\n        <input type="email" id="email" name="email" required>\n\n        <label for="phone">Phone:</label>\n        <input type="tel" id="phone" name="phone" required>\n\n        <label for="company">Company/Branch:</label>\n        <input type="text" id="company" name="company">\n\n        <label for="tour_details">Tour Details:</label>\n        <textarea id="tour_details" name="tour_details" required></textarea>\n\n        <button type="submit">Send Credentials via WhatsApp</button>\n    </form>\n</body>\n</html>